def generate(level=1, **kwargs):
    circumference_cm = 130
    rpm_symbol = "rpm"
    requested_unit = "km/h"

    # Convert circumference to km: 130 cm = 130 / 100000 km = 13 / 10000 km
    # Speed for 1 rpm = (13 / 10000) km per rpm
    # To get km/h: multiply by 60 (minutes in an hour)
    # So: (13 / 10000) * 60 = (13 * 60) / 10000 = 780 / 10000
    # Reduce 780 / 10000: divide numerator and denominator by 20
    # 780 ÷ 20 = 39, 10000 ÷ 20 = 500 → 39 / 500

    from fractions import Fraction

    coefficient_fraction = Fraction(780, 10000)
    reduced_coefficient = coefficient_fraction.reduce()

    # Format as string: if denominator is 1, output integer; otherwise "p/q"
    if reduced_coefficient.denominator == 1:
        coefficient_str = str(reduced_coefficient.numerator)
    else:
        coefficient_str = f"{reduced_coefficient.numerator}/{reduced_coefficient.denominator}"

    return {
        "question_text": f"Calculate the linear speed in km/h for 1 {rpm_symbol} given a wheel circumference of {circumference_cm} cm.",
        "correct_answer": {
            "coefficient": coefficient_str,
            "unit": "km/h"
        },
        "oracle_payload": {
            "circumference_cm": 130,
            "requested_unit": "km/h",
            "rpm_symbol": "rpm"
        }
    }
